const { spawnSync } = require('child_process');

const itemIndex = $itemIndex ?? 0;
const inputItem = $input.item;
if (!inputItem) throw new Error('No input item received');

function pickAttachment(binary) {
  const keys = Object.keys(binary || {});
  const key =
    keys.find(k => {
      const b = binary[k] || {};
      const mime = (b.mimeType || '').toLowerCase();
      const name = (b.fileName || '').toLowerCase();
      return mime.includes('spreadsheet') || mime.includes('excel') ||
        mime.includes('openxmlformats') || name.endsWith('.xlsx');
    }) || keys.find(k => k.startsWith('attachment_')) || keys[0];

  return { key, keys };
}

const binary = inputItem.binary || {};
const { key: attachmentKey, keys: allKeys } = pickAttachment(binary);
if (!attachmentKey) throw new Error('No attachment found. Keys: ' + allKeys.join(', '));

let buffer;
try {
  buffer = await this.helpers.getBinaryDataBuffer(itemIndex, attachmentKey);
} catch (helperErr) {
  const inline = (binary[attachmentKey].data || '').replace(/-/g, '+').replace(/_/g, '/');
  if (inline && inline.length > 100) {
    buffer = Buffer.from(inline, 'base64');
  } else {
    throw new Error(
      `Failed to read attachment "${attachmentKey}" from binary storage: ${helperErr.message}`
    );
  }
}

const b64 = buffer.toString('base64');
if (!b64 || b64.length < 100) {
  throw new Error(`Attachment data too small (${b64.length} chars)`);
}

const result = spawnSync(
  '/Users/priyanshupatel/Documents/GitHub/personal/venv/bin/python3',
  ['/Users/priyanshupatel/Documents/GitHub/personal/src/preprocessing.py', '-'],
  { input: b64, encoding: 'utf8', timeout: 120000 }
);

if (result.error) throw new Error('Python spawn error: ' + result.error.message);
if (result.status !== 0) throw new Error('Preprocessing failed:\n' + result.stderr);

const stdout = (result.stdout || '').trim();
let parsed;
try { parsed = JSON.parse(stdout); }
catch(e) { throw new Error('Could not parse preprocessing output:\n' + stdout); }

if (parsed.error) throw new Error('Preprocessing error: ' + parsed.error);

const triggerJson = $('Gmail Trigger').item.json;
return {
  json: {
    ...parsed,
    senderEmail: triggerJson.from?.value?.[0]?.address || triggerJson.from || '',
    originalSubject: triggerJson.subject || 'CRM Export',
  }
};

const { spawnSync } = require('child_process');

const cleanFilePath = item.json.clean_file_path;
if (!cleanFilePath) throw new Error('clean_file_path missing from preprocessing output');

const meta = JSON.stringify({
  total_rows_clean: item.json.total_rows_clean,
  processing_date:  item.json.processing_date,
  timestamp:        item.json.timestamp,
});

const result = spawnSync(
  '/Users/priyanshupatel/Documents/GitHub/personal/venv/bin/python3',
  ['/Users/priyanshupatel/Documents/GitHub/personal/src/formatting.py', cleanFilePath, meta],
  { encoding: 'utf8', timeout: 180000 }
);

if (result.error) throw new Error('Python spawn error: ' + result.error.message);
if (result.status !== 0) throw new Error('Formatting failed:\n' + result.stderr);

const stdout = (result.stdout || '').trim();
let parsed;
try { parsed = JSON.parse(stdout); }
catch(e) { throw new Error('Could not parse formatting output:\n' + stdout); }

if (!parsed.success) throw new Error('Formatting error: ' + (parsed.error || 'Unknown'));

return {
  json: {
    ...item.json,
    formattedFilePath: parsed.formatted_file_path,
    formattedFileName: parsed.formatted_file_path.split('/').pop(),
    formattingSuccess: parsed.success,
  }
};

const p = item.json;

function fmt(n) { return Number(n || 0).toLocaleString('en-US'); }
function fmtRpm(n) { return '$' + Number(n || 0).toFixed(0); }

const top3Text = (p.top_3_clients || [])
  .map(function(c, i) {
    return (i+1) + '. ' + (c.client_name || 'Unknown') + ' — Revenue $' + fmt(c.revenue_usd);
  }).join('\n');

const bottom3Text = (p.bottom_3_rpm_clients || [])
  .map(function(c, i) {
    return (i+1) + '. ' + (c.client_name || c.Client_Name || 'Unknown') + ' — Rev/Meeting $' + fmtRpm(c.rev_per_meeting || c.Rev_Per_Meeting);
  }).join('\n');

const flaggedText = (p.flagged_clients_list || []).slice(0, 8)
  .map(function(c) {
    return '- ' + (c.client_name || 'Unknown') + ': ' + (c.meetings_cnt||0) + ' meetings, Revenue $' + fmt(c.revenue_usd);
  }).join('\n') || 'None';

const mifidText = (p.expired_mifid_list || []).slice(0, 8)
  .map(function(c) {
    return '- ' + (c.client_name || c.Client_Name || 'Unknown') + ' (Expiry: ' + (c.mifid_expiry||c.MiFID_Expiry_Date||'Unknown') + ')';
  }).join('\n') || 'None';

const regionEntries = Object.entries(p.region_summary || {})
  .filter(function(e) { return e[0] !== 'UNKNOWN'; });
const regionText = regionEntries.length > 0
  ? regionEntries.map(function(e) {
      const r = e[0], v = e[1];
      if (typeof v === 'object' && v !== null) {
        return '- ' + r + ': ' + (v.client_count||0) + ' clients, Revenue $' + fmt(v.total_revenue) + ', Avg Meetings ' + (v.avg_meetings||0);
      }
      return '- ' + r + ': Revenue $' + fmt(v);
    }).join('\n')
  : '(No regional data — REGION field is blank in source CRM file.)';

const tierText = Object.entries(p.tier_summary || {})
  .map(function(e) {
    const t = e[0], v = e[1];
    return '- ' + t + ': ' + (v.client_count||0) + ' clients, Revenue $' + fmt(v.total_revenue);
  }).join('\n');

const prompt = [
  'You are a senior Fixed Income analyst at Nomura Securities.',
  'Produce an executive briefing note for the Head of Fixed Income Client Management.',
  '',
  '=== CRITICAL OUTPUT RULES ===',
  '1. Return ONLY raw HTML — zero markdown, zero code fences, zero ```html wrappers.',
  '2. Do NOT wrap output in <html>, <head>, or <body> tags.',
  '3. Start your response DIRECTLY with the first HTML element (e.g., <h3 ...>).',
  '4. Use ONLY inline CSS styles. No <style> blocks. No class attributes.',
  '5. Use Nomura brand colors: dark navy #1F3864, medium blue #2E75B6, light blue #EBF3FB.',
  '6. CRITICAL: For sections 3 and 4 use ONLY <ul>/<li> lists — NO <table> tags in those sections.',
  '7. You MAY use <table> ONLY in section 5 for the regional/tier breakdown.',
  '',
  '=== HTML STYLE GUIDE ===',
  'Section header: <h3 style="color:#1F3864;font-size:14px;font-weight:bold;border-bottom:2px solid #2E75B6;padding-bottom:4px;margin:20px 0 10px;">TITLE</h3>',
  'Paragraph: <p style="font-size:13px;line-height:1.7;margin:6px 0;color:#333;">text</p>',
  'Bullet list: <ul style="font-size:13px;line-height:1.8;padding-left:20px;margin:6px 0;"><li style="margin:4px 0;">item</li></ul>',
  'Blue highlight (positive): <strong style="color:#2E75B6;">value</strong>',
  'Red highlight (warning): <strong style="color:#C00000;">value</strong>',
  'Section 5 table ONLY: <table style="border-collapse:collapse;width:100%;margin:10px 0;">',
  'Table header row: <tr style="background:#2E75B6;color:#fff;">',
  'Table header cell: <th style="padding:7px 12px;text-align:left;font-size:12px;">col</th>',
  'Table data cell (odd rows): <td style="padding:7px 12px;border:1px solid #dde3ed;font-size:12px;background:#fff;">val</td>',
  'Table data cell (even rows): <td style="padding:7px 12px;border:1px solid #dde3ed;font-size:12px;background:#EBF3FB;">val</td>',
  '',
  '=== CRM DATA ===',
  'Report Date: ' + p.processing_date,
  'Total Active Clients: ' + p.total_rows_clean,
  'Records Removed: ' + p.rows_removed,
  'Null Fields: ' + (p.null_count || 0),
  'MiFID Expired: ' + p.expired_mifid_count,
  'MiFID Status Unknown: ' + (p.unknown_mifid_count || 0),
  'Clients Flagged for Review: ' + p.flagged_clients_count,
  'Research Access Pending: ' + (p.research_access_pending_count || 0),
  '',
  'Top Analyst: ' + p.top_analyst_name + ' (Revenue: $' + fmt(p.top_analyst_revenue) + ')',
  'Lowest Efficiency Analyst: ' + p.worst_analyst_name + ' (Rev/Meeting: ' + fmtRpm(p.worst_analyst_rpm) + ')',
  '',
  'Top 3 Revenue Clients:',
  top3Text,
  '',
  'Bottom 3 by Revenue/Meeting Efficiency:',
  bottom3Text,
  '',
  'Regional Breakdown:',
  regionText,
  '',
  'Tier Breakdown:',
  tierText,
  '',
  'Clients Flagged (High Meetings, Low Revenue):',
  flaggedText,
  '',
  'MiFID Expired Clients:',
  mifidText,
  '',
  '=== REQUIRED SECTIONS (ALL SIX, in order) ===',
  '',
  '1. EXECUTIVE SUMMARY',
  '   2-3 paragraphs. Reference total_rows_clean, rows_removed, expired_mifid_count, flagged_clients_count.',
  '',
  '2. ANALYST PERFORMANCE',
  '   Name top and worst analyst. Quantify the efficiency gap. Use <ul>/<li> for each analyst.',
  '',
  '3. CLIENT RISK FLAGS',
  '   Use ONLY <ul>/<li> — NO tables. List each flagged client with meetings, revenue, and why it is a concern.',
  '',
  '4. MiFID COMPLIANCE ACTIONS',
  '   Use ONLY <ul>/<li> — NO tables. List each expired client by name and expiry. List unknown-status clients separately.',
  '   State regulatory consequence and give 3 numbered remediation steps.',
  '',
  '5. REGIONAL AND TIER INSIGHTS',
  '   If Regional Breakdown above says No regional data, write ONE <p> stating data is unavailable — do NOT invent any numbers.',
  '   Otherwise use ONE <table> for the regional breakdown (columns: Region, Clients, Revenue, Avg Meetings).',
  '   Use a second <table> for tier breakdown (Tier, Clients, Revenue).',
  '   Identify strongest and weakest regions and tier concentration risk.',
  '',
  '6. RECOMMENDED ACTIONS',
  '   Exactly 6 <li> bullet points in a <ul>, prioritised by urgency.',
  '   Each must reference a specific client name, analyst name, or exact number.',
  '',
  'Tone: executive, data-led, direct. Minimum 650 words. Every claim must cite a specific figure.'
].join('\n');

const payload = {
  generationConfig: { temperature: 0.2, maxOutputTokens: 8192 },
  contents: [{ role: 'user', parts: [{ text: prompt }] }]
};

return { json: { ...item.json, geminiBody: JSON.stringify(payload), aiPrompt: prompt } };

const preproc = $('Run Preprocessing').item.json;
const formatting = $('Run Formatting').item.json;

function tryParseJson(value) {
  if (typeof value !== 'string') return value;
  const trimmed = value.trim();
  if (!trimmed) return value;
  if (!(trimmed.startsWith('{') || trimmed.startsWith('['))) return value;
  try { return JSON.parse(trimmed); } catch (e) { return value; }
}

function unwrapPayload(payload) {
  let current = payload;
  for (let i = 0; i < 5; i++) {
    if (typeof current === 'string') {
      const parsed = tryParseJson(current);
      if (parsed === current) break;
      current = parsed;
      continue;
    }
    if (!current || typeof current !== 'object') break;
    if (typeof current.body === 'string') {
      const pb = tryParseJson(current.body);
      if (pb !== current.body) { current = pb; continue; }
    }
    if (typeof current.data === 'string') {
      const pd = tryParseJson(current.data);
      if (pd !== current.data) { current = pd; continue; }
    }
    if (current.body && typeof current.body === 'object' && current.body !== current) { current = current.body; continue; }
    if (current.data && typeof current.data === 'object' && current.data !== current) { current = current.data; continue; }
    break;
  }
  return current;
}

function extractGeminiText(payload) {
  const source = unwrapPayload(payload);
  const candidates = [];
  if (source && typeof source === 'object') {
    candidates.push(source);
    if (Array.isArray(source.candidates) && source.candidates.length) {
      candidates.push(source.candidates[0]);
    }
  }
  for (const candidate of candidates) {
    const parts = candidate?.content?.parts || candidate?.parts || [];
    const text = Array.isArray(parts) ? parts.map(p => p?.text || '').join('').trim() : '';
    if (text) return text;
    if (typeof candidate?.text === 'string' && candidate.text.trim()) return candidate.text.trim();
    if (typeof candidate?.content === 'string' && candidate.content.trim()) return candidate.content.trim();
  }
  if (typeof source === 'string' && source.trim()) return source.trim();
  return '';
}

// Close any unclosed HTML table structure tags to prevent layout breakage in email
function sanitizeTableHTML(html) {
  const openTd    = (html.match(/<td[^>]*>/gi)  || []).length;
  const closeTd   = (html.match(/<\/td>/gi)     || []).length;
  const openTh    = (html.match(/<th[^>]*>/gi)  || []).length;
  const closeTh   = (html.match(/<\/th>/gi)     || []).length;
  const openTr    = (html.match(/<tr[^>]*>/gi)  || []).length;
  const closeTr   = (html.match(/<\/tr>/gi)     || []).length;
  const openTable = (html.match(/<table[^>]*>/gi) || []).length;
  const closeTable= (html.match(/<\/table>/gi)  || []).length;
  let suffix = '';
  for (let i = 0; i < openTd    - closeTd;    i++) suffix += '</td>';
  for (let i = 0; i < openTh    - closeTh;    i++) suffix += '</th>';
  for (let i = 0; i < openTr    - closeTr;    i++) suffix += '</tr>';
  for (let i = 0; i < openTable - closeTable; i++) suffix += '</table>';
  return html + suffix;
}

// Extract raw text from Gemini response
let rawText = extractGeminiText($json).trim();

// Strip any code fences Gemini might add despite instructions
rawText = rawText
  .replace(/^```html\s*/i, '')
  .replace(/^```\s*/i, '')
  .replace(/```\s*$/i, '')
  .trim();

// Fix small-model markdown output (Gemma etc.) before HTML detection
// 1. ![Section Name](url) or ![Section Name]() → <h3> header
rawText = rawText.replace(/!\[([^\]]+)\]\([^)]*\)/g, function(_, label) {
  return '<h3 style="color:#1F3864;font-size:14px;font-weight:bold;border-bottom:2px solid #2E75B6;padding-bottom:4px;margin:20px 0 10px;">' + label + '</h3>';
});
// 2. Remaining bare ![text] with no parens
rawText = rawText.replace(/!\[([^\]]+)\]/g, function(_, label) {
  return '<h3 style="color:#1F3864;font-size:14px;font-weight:bold;border-bottom:2px solid #2E75B6;padding-bottom:4px;margin:20px 0 10px;">' + label + '</h3>';
});
// 3. Markdown headers ## or # → <h3>
rawText = rawText.replace(/^#{1,3}\s+(.+)$/gm, function(_, title) {
  return '<h3 style="color:#1F3864;font-size:14px;font-weight:bold;border-bottom:2px solid #2E75B6;padding-bottom:4px;margin:20px 0 10px;">' + title + '</h3>';
});
// 4. **bold** → <strong>
rawText = rawText.replace(/\*\*([^*]+)\*\*/g, '<strong style="color:#1F3864;">$1</strong>');
// 5. Markdown bullets * item or - item (outside HTML context)
rawText = rawText.replace(/^[*-]\s+(.+)$/gm, '<li style="margin:4px 0;font-size:13px;line-height:1.7;">$1</li>');

// If Gemini returned plain text (no HTML tags), convert to basic HTML
const hasHtmlTags = /<[a-z][\s\S]*>/i.test(rawText);
let aiBriefing;
if (!rawText) {
  aiBriefing = '<p style="color:#C00000;font-size:13px;">AI briefing unavailable.</p>';
} else if (!hasHtmlTags) {
  const lines = rawText.split('\n');
  const htmlLines = lines.map(function(line) {
    const trimmed = line.trim();
    if (!trimmed) return '';
    if (/^\d+\.\s+[A-Z\s]{4,}/.test(trimmed)) {
      return '<h3 style="color:#1F3864;font-size:14px;font-weight:bold;border-bottom:2px solid #2E75B6;padding-bottom:4px;margin:20px 0 10px;">' + trimmed + '</h3>';
    }
    if (/^[-*•]\s+/.test(trimmed)) {
      return '<li style="margin:3px 0;font-size:13px;line-height:1.7;">' + trimmed.replace(/^[-*•]\s+/, '') + '</li>';
    }
    return '<p style="font-size:13px;line-height:1.7;margin:6px 0;color:#333;">' + trimmed + '</p>';
  });
  let html = htmlLines.join('\n');
  html = html.replace(/(<li[^>]*>.*?<\/li>\n?)+/gs, function(m) {
    return '<ul style="font-size:13px;line-height:1.8;padding-left:20px;margin:8px 0;">' + m + '</ul>';
  });
  aiBriefing = html;
} else {
  // Sanitize table structure to fix any unclosed tags that would break the email layout
  aiBriefing = sanitizeTableHTML(rawText);
}

return {
  json: {
    senderEmail: preproc.senderEmail,
    originalSubject: preproc.originalSubject,
    processing_date: preproc.processing_date,
    total_rows_clean: preproc.total_rows_clean,
    rows_removed: preproc.rows_removed,
    expired_mifid_count: preproc.expired_mifid_count,
    flagged_clients_count: preproc.flagged_clients_count,
    top_analyst_name: preproc.top_analyst_name,
    null_count: preproc.null_count,
    duplicate_count: preproc.duplicate_count,
    aiBriefing,
    formattedFilePath: formatting.formattedFilePath,
    formattedFileName: formatting.formattedFileName,
  },
};
